#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Node{
    Node *son[2];
}*root;

int n,a[N],ans;

int main(){
    root=new Node;
    root->son[0]=root->son[1]=NULL;
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        if(i>1){
            int sum=0;
            Node *p=root;
            for(int j=30;j>=0;j--){
                if(p->son[((bool)(a[i]&(1<<j)))^1]!=NULL)
                    p=p->son[((bool)(a[i]&(1<<j)))^1],sum+=(1<<j);
                else
                    p=p->son[(bool)(a[i]&(1<<j))];
			}
            ans=max(ans,sum);
        }
        Node *p=root;
        for(int j=30;j>=0;j--){
            if(p->son[(bool)(a[i]&(1<<j))]==NULL){
                Node *q=new Node;
                q->son[0]=q->son[1]=NULL;
                p->son[(bool)(a[i]&(1<<j))]=q;
            }
            p=p->son[(bool)(a[i]&(1<<j))];
        }
    }
    printf("%d",ans);
    return 0;
}
